import React, { useState } from "react";

// Componente del ícono de usuario (SVG)
const UserIcon = () => (
  <svg style={{ width: "50px", height: "50px", fill: "#333" }} viewBox="0 0 24 24">
    <path d="M12 12c2.76 0 5-2.24 5-5S14.76 2 12 2 7 4.24 7 7s2.24 5 5 5zm0 2c-3.33 0-10 1.67-10 5v3h20v-3c0-3.33-6.67-5-10-5z" />
  </svg>
);

const InicioSesion = ({ onLogin, onClose }) => {
  const [usuario, setUsuario] = useState("");
  const [contrasena, setContrasena] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!usuario || !contrasena) {
      alert("Por favor, rellena todos los campos");
      return;
    }
    if (onLogin) {
      onLogin({ usuario, contrasena });
    } else {
      console.log({ usuario, contrasena });
    }
  };

  // Overlay oscuro que abarca la parte inferior de la página para dar contraste
  const estilosOverlay = {
    position: "fixed",
    bottom: 0,
    left: 0,
    right: 0,
    backgroundColor: "rgba(0,0,0,0.7)", // Fondo oscuro semitransparente
    padding: "20px 0",
    display: "flex",
    justifyContent: "center",
    zIndex: 9999,
  };

  // Recuadro (modal) principal con fondo beige semi-transparente y bordes redondeados
  const estilosModal = {
    position: "relative",
    backgroundColor: "rgba(245,245,220,0.95)", // Beige con ligera transparencia
    borderRadius: "15px",
    padding: "40px 20px 20px 20px",
    width: "350px",
    textAlign: "center",
    boxShadow: "0 2px 8px rgba(0,0,0,0.3)",
  };

  // Estilos para el ícono de persona; está centrado y sobresale por encima del modal
  const estilosIcono = {
    position: "absolute",
    top: "-30px",
    left: "50%",
    transform: "translateX(-50%)",
    backgroundColor: "rgba(245,245,220,0.95)",
    borderRadius: "50%",
    padding: "10px",
    boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
  };

  // Botón "X" para cerrar el recuadro, ubicado en la esquina superior derecha
  const estilosCerrar = {
    position: "absolute",
    top: "10px",
    right: "10px",
    background: "none",
    border: "none",
    fontSize: "20px",
    cursor: "pointer",
    color: "#333",
  };

  // Título en mayúsculas, con un tipo de letra atractivo
  const estilosTitulo = {
    marginTop: "30px",
    marginBottom: "20px",
    fontSize: "22px",
    fontWeight: "bold",
    color: "#333",
    textAlign: "center",
    textTransform: "uppercase",
    fontFamily: "'Poppins', sans-serif",
  };

  // Inputs con borde gris, centrados y con fondo blanco
  const estilosInput = {
    width: "90%",
    padding: "10px",
    margin: "10px auto",
    fontSize: "16px",
    border: "1px solid #ccc",
    borderRadius: "8px",
    background: "#fff",
    textAlign: "center",
    outline: "none",
    color: "#333",
  };

  // Botón "Enviar" centrado, con estilo moderno
  const estilosBoton = {
    width: "90%",
    padding: "10px",
    margin: "20px auto 0 auto",
    fontSize: "16px",
    cursor: "pointer",
    border: "none",
    backgroundColor: "#007bff",
    color: "#fff",
    borderRadius: "8px",
    display: "block",
  };

  return (
    <div style={estilosOverlay}>
      <div style={estilosModal}>
        {onClose && (
          <button style={estilosCerrar} onClick={onClose}>
            X
          </button>
        )}
        <div style={estilosIcono}>
          <UserIcon />
        </div>
        <div style={estilosTitulo}>INICIO DE SESIÓN</div>
        <form onSubmit={handleSubmit}>
          <input
            type="text"
            placeholder="Usuario"
            value={usuario}
            onChange={(e) => setUsuario(e.target.value)}
            style={estilosInput}
          />
          <input
            type="password"
            placeholder="Contraseña"
            value={contrasena}
            onChange={(e) => setContrasena(e.target.value)}
            style={estilosInput}
          />
          <button type="submit" style={estilosBoton}>
            Enviar
          </button>
        </form>
      </div>
    </div>
  );
};

export default InicioSesion;
